"""
MKT Context Commentary — Proverbs chapters 13–15
Run: python3 scripts/zc-context-proverbs-13-15.py
Context focus:
- Ch13: sentence-collection register; tree of life (v12) third occurrence; lamp imagery
- Ch14: wise/foolish woman (v1) as domestic embodiment of ch1-9's personification
- Ch14:12 — the path-that-seems-right as a key diagnostic proverb
- Ch14:31 — creation-theology of the poor: Maker identified with the poor person
- Ch15: divine omniscience (v3); Sheol/Abaddon open before God (v11);
         prophetic critique of wicked sacrifice (v8); better-than proverbs (vv16-17)
- Ch15:33 — fear of the LORD as wisdom's discipline; humility before honor
"""

import json, pathlib
ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

new_data = {
    "13": {
        "1": "<p>The wise son / mocker pairing that opens ch13 is the fundamental didactic contrast of Proverbs&#8217; sentence-collection (chs.&#160;10&#8211;22). Unlike chs.&#160;1&#8211;9 with their extended discourses, chs.&#160;10ff. present individual proverbs assembled into loose thematic clusters. The wise son who heeds instruction versus the mocker who refuses rebuke encapsulates the entire book&#8217;s pedagogical stakes in one line. The mocker (<i>lēṣ</i>) is Proverbs&#8217; most dangerous character type: not the ignorant who can be taught but the contemptuous who refuse to be.</p>",
        "2": "<p>&#8220;A man eats well from the fruit of his words&#8221; — the organic metaphor of speech as agricultural produce is a characteristic wisdom insight. Words have outcomes the way planting has harvests; the speaker who sows good words reaps a well-fed life. The same agricultural-speech metaphor appears in Matt&#160;12:33&#8211;37 (&#8220;out of the abundance of the heart the mouth speaks&#8221;) and Jas&#160;3:11&#8211;12 (the spring and its fruit). The wisdom tradition consistently connects the quality of speech to the interior moral state from which it flows.</p>",
        "3": "<p>&#8220;Whoever guards his mouth protects his life&#8221; (cf. 21:23) is the inverse formulation of what becomes James&#8217;s extended teaching on the tongue (Jas&#160;3:2&#8211;12). In the ancient world where reputation and social standing depended heavily on public speech, the person who controlled their words controlled their destiny. The Egyptian Instruction of Amenemope dedicates extensive sections to the discipline of speech, recognizing it as the central skill of the well-formed person. Proverbs is consistent: unguarded speech is existentially dangerous.</p>",
        "4": "<p>&#8220;The diligent soul is richly satisfied (<i>mᵉduššānāh</i>)&#8221; — the diligence-versus-sloth contrast is one of Proverbs&#8217; most persistent ethical themes (6:6&#8211;11; 10:4; 12:24; 21:25). The word <i>dāšēn</i> (to be fat, richly satisfied — used of well-fed animals and the satisfaction of abundance) pictures the diligent person as one who has eaten their fill. Against the Greek tendency to view manual labor and practical work as beneath the philosophical life, the Hebrew wisdom tradition celebrates diligent labor as the path to genuine satisfaction.</p>",
        "5": "<p>&#8220;A righteous man hates falsehood (<i>dᵉbar-šeqer</i>)&#8221; — the connection between righteousness and hatred of falsehood is grounded in YHWH&#8217;s character: he is a God of truth (<i>ʾel ʾĕmet</i>, Deut&#160;32:4; Ps&#160;31:5; Isa&#160;65:16) who &#8220;detests lying lips&#8221; (Prov&#160;12:22). The righteous person embodies the divine character by sharing the divine attitude toward lies. The &#8220;disgrace (<i>hibbîš</i>)&#8221; and &#8220;shame (<i>yaḥpîr</i>)&#8221; of the wicked man are the social consequences of the character that YHWH detests.</p>",
        "6": "<p>&#8220;Righteousness guards the one who walks uprightly, but wickedness brings down the sinner.&#8221; The personification of righteousness as a guardian (<i>šōmeret</i>) gives this verse a theological density beyond the merely ethical. Righteousness is not just a quality one possesses but an active protecting force — because righteousness aligns the person with the moral order YHWH has built into the world, and that order acts as protection. The wicked person&#8217;s destruction (<i>sillēp</i>, to subvert, overthrow) is likewise the world&#8217;s moral order acting on the one who defies it.</p>",
        "7": "<p>&#8220;One acts rich and has nothing; another acts poor yet has great wealth.&#8221; This observation of the gap between social performance and reality reflects the wisdom tradition&#8217;s consistent suspicion of appearances. The two types are not condemned here but observed — perhaps the self-promoter versus the genuinely wealthy person who conceals wealth. The verse connects to the broader theme of honest speech: how one represents oneself to others should match reality. The reversal of appearances is a favorite wisdom device (cf. 12:9; 30:7&#8211;9).</p>",
        "8": "<p>&#8220;A man&#8217;s wealth may ransom his life, but a poor man hears no threatening.&#8221; Ransom (<i>kōper</i>) in the legal sense — paying to escape a capital penalty (Exod&#160;21:30; Num&#160;35:31) — was possible for the wealthy but not for the poor. The verse observes a social asymmetry without endorsing it: the wealthy face a threat the poor do not (kidnappers, extortionists targeting ransom) but have the means to escape it; the poor face many threats but not this one. Wealth is a mixed gift that creates its own vulnerabilities.</p>",
        "9": "<p>&#8220;The light of the righteous shines with joy (<i>yiśmāḥ</i>), but the lamp of the wicked will be extinguished (<i>yidʿāk</i>).&#8221; The light-lamp image for life and prosperity (10:27; 20:20; 24:20) draws on the practical reality that a lamp in the house was a sign of life: an extinguished lamp meant either death or poverty. The righteous&#8217; light &#8220;shines with joy&#8221; — it is joyful, festive light; the wicked&#8217;s lamp goes out entirely. The same metaphor appears in Job&#160;18:5&#8211;6; 21:17 and Ps&#160;18:28 (&#8220;you light my lamp, O LORD&#8221;).</p>",
        "10": "<p>&#8220;Pride produces nothing but conflict (<i>rîb</i>), but wisdom is found in those who take counsel (<i>nôʿāṣîm</i>).&#8221; The connection between pride and conflict is consistent across the wisdom tradition (11:2; 16:18; 21:24) and corresponds to James&#8217;s teaching: &#8220;what causes quarrels and fights? Is it not this, that your passions are at war within you?&#8221; (Jas&#160;4:1). The proud person who insists on their own way creates friction at every point where they encounter resistance. The counsel-seeking person, by contrast, builds the community of wisdom that Proverbs consistently commends (11:14; 15:22; 24:6).</p>",
        "11": "<p>&#8220;Wealth gained by fraud will shrink, but whoever gathers it gradually through labor will see it grow.&#8221; The contrast between fraudulent quick-gain and patient labor echoes the wisdom tradition&#8217;s consistent anti-fraud teaching (20:17; 21:6) and its commendation of steady diligent work. The organic metaphor — wealth that shrinks like melting vapor versus wealth that grows — draws on agricultural experience: crops planted and tended grow; food stolen or grabbed rots. The principle anticipates the economic insight that sustainable wealth requires the kind of work that creates real value.</p>",
        "12": "<p>&#8220;Hope deferred makes the heart grow sick, but a longing fulfilled is a tree of life.&#8221; The third tree-of-life occurrence in Proverbs (3:18; 11:30; 13:12) here applies the symbol not to wisdom itself but to fulfilled desire. The <i>ʿēṣ ḥayyîm</i> (tree of life) is the experience of getting what you truly longed for — it restores and revives as the Eden tree was meant to. The psychological observation about deferred hope is universally attested in human experience and anticipates modern understanding of hope&#8217;s physiological effects. The heart&#8217;s sickness from perpetual deferral is the emotional cost of unfulfilled promise.</p>",
        "13": "<p>&#8220;Whoever despises instruction will be brought to ruin (<i>yēḥābel</i>), but whoever respects the commandment will be rewarded.&#8221; The verse bridges the wisdom and legal traditions: &#8220;commandment (<i>miṣwāh</i>)&#8221; is the standard term for Mosaic law (Deut&#160;4:2; 6:1&#8211;2), placing wisdom instruction within the frame of covenant obligation. Contempt for instruction (<i>dābār</i>) is not merely poor judgment but a covenant violation. The Deuteronomic warning that those who despise the word will perish (Deut&#160;28:15&#8211;20) is here compressed into a single proverb.</p>",
        "14": "<p>&#8220;The teaching of the wise is a fountain of life (<i>mᵉqôr ḥayyîm</i>), turning one away from the traps of death.&#8221; The fountain-of-life image (10:11; 14:27; 16:22) is the wisdom counterpart to the life-giving streams of the Psalms (Ps&#160;1:3; 36:9; 46:4). In the dry climate of Palestine, a fountain was not merely pleasant but life-sustaining — a source that gave water even in drought. Wisdom is presented as that kind of essential resource: not optional enrichment but the life-supply that keeps the person from the death-traps that line every path. Jesus applies this metaphor to himself explicitly (John&#160;4:14; 7:38).</p>",
        "15": "<p>&#8220;Good understanding wins favor (<i>ḥēn</i>), but the way of the treacherous leads to their ruin (<i>ʾêtān</i>).&#8221; <i>Śēkel ṭôb</i> (good understanding/insight) produces social favor — the recognition and positive regard of those who observe wisdom in action. This is the social confirmation that wisdom&#8217;s self-investment in understanding is worthwhile: the community recognizes and honors what wisdom has shaped. Treachery (the utter-faithlessness of those who cannot be trusted) leads to the hardest kind of ruin — &#8220;<i>ʾêtān</i>&#8221; (the word may mean &#8220;perennial, enduring&#8221; — suggesting a permanent and settled condition of ruin).</p>",
        "16": "<p>&#8220;Every prudent person acts from knowledge, but a fool broadcasts his foolishness.&#8221; The contrast is not between knowledge and ignorance but between knowing-and-acting and having-nothing-to-show. The prudent person&#8217;s knowledge is expressed in purposeful action; the fool&#8217;s inner state is emptiness that spills out as noise. The Egyptian Instruction tradition consistently warns against excessive speech as the marker of the unformed person; those who have been well-formed keep their counsel and act from understanding rather than broadcasting every impulse.</p>",
        "17": "<p>&#8220;A wicked messenger causes harm, but a trustworthy envoy brings healing.&#8221; The messenger was a crucial figure in the ancient world — the bearer of news, commands, and diplomatic communications. An unreliable messenger could cause international incidents, lost battles, or missed opportunities (cf. 2&#160;Sam&#160;18:19&#8211;33 for the dramatic consequences of a messenger&#8217;s report). The word <i>malkût</i> (envoy, <i>ṣîr</i>) — a court official. The proverb has direct application to anyone entrusted with important communications: the integrity of the messenger shapes the outcome for everyone involved.</p>",
        "18": "<p>&#8220;Poverty and disgrace come to whoever refuses discipline, but honor comes to whoever accepts correction.&#8221; The structural parallel between poverty-and-disgrace versus honor maps the material consequences onto the social ones: refusing formative correction produces not just inner moral deterioration but external poverty and public shame. Accepting correction (<i>tôkaḥat</i>) produces honor. The wisdom tradition does not separate the inner life from its outer consequences: character shapes destiny in ways that are both personal and social.</p>",
        "19": "<p>&#8220;A longing fulfilled is sweet to the soul, but fools find it revolting to turn from evil.&#8221; The verse links back to v12&#8217;s tree-of-life for fulfilled longing but adds the diagnostic twist: the obstacle to fulfillment for fools is not external deprivation but their own refusal to change. The fool has desires (v4) and can imagine satisfaction (v19a) but finds the cost — turning from evil — more revolting than the desire is compelling. This is the psychological portrait of the person whose love for their sin exceeds their desire for their own good.</p>",
        "20": "<p>&#8220;Walk with the wise and you will become wise, but whoever befriends fools will suffer harm.&#8221; The formative power of social environment is one of Proverbs&#8217; practical insights. Character is shaped not only by instruction but by association: the people we habitually spend time with shape our habits of thought and action. This is consistent with modern understanding of moral formation through social modeling. The warning about befriending fools is not snobbery but realism about moral contagion: the fool&#8217;s patterns of thought and action are transmitted through sustained contact. Paul quotes a version of this principle in 1&#160;Cor&#160;15:33 (&#8220;bad company corrupts good morals&#8221;).</p>",
        "21": "<p>&#8220;Calamity pursues (<i>rādap</i>) sinners, but the righteous will be rewarded with good.&#8221; The pursuit-language (<i>rādap</i> — to chase, hunt down) personifies calamity as a predator tracking the sinner. This is the organic retribution pattern characteristic of wisdom: the consequences of sin have a hunter&#8217;s persistence. Psalm&#160;23:6 reverses this: &#8220;surely goodness and steadfast love will pursue (<i>rādap</i>) me all the days of my life&#8221; — for the righteous, it is blessing that hunts them down. The same verb captures both trajectories.</p>",
        "22": "<p>&#8220;A good man leaves an inheritance for his grandchildren, but the wealth of a sinner is stored up for the righteous.&#8221; Generational blessing is a covenant theme: Abraham&#8217;s blessing explicitly includes his descendants (Gen&#160;12:2&#8211;3; 17:7; Deut&#160;7:9). The good man&#8217;s inheritance across three generations (himself, his children, his grandchildren) is the concrete expression of covenant blessing in family terms. The reversal — sinner&#8217;s wealth ultimately going to the righteous — is the wisdom tradition&#8217;s claim that the moral order of the universe corrects even economic injustice in the long run (Prov&#160;28:8; Eccl&#160;2:26).</p>",
        "23": "<p>&#8220;The land of the poor may produce abundant food, but it is swept away through injustice.&#8221; A social observation about the structural injustice that can defeat the poor person&#8217;s labor: even when their land produces, the produce can be taken away. This verse participates in the prophetic critique of economic exploitation (Amos&#160;2:6&#8211;7; 5:11; Isa&#160;3:14&#8211;15; Mic&#160;2:1&#8211;2). The wisdom tradition is not indifferent to structural injustice; it recognizes that the poor&#8217;s poverty is often the result of powerful others&#8217; wickedness, not the poor person&#8217;s own failure.</p>",
        "24": "<p>&#8220;Whoever spares the rod hates his son, but whoever loves him disciplines him while there is time.&#8221; The rod-and-love paradox of parental discipline is a touchstone verse (cf. 19:18; 22:15; 23:13&#8211;14; 29:15, 17). In the ancient world, physical correction was the standard means of character formation; the wisdom tradition consistently connects it to love, not cruelty. Hebrews&#160;12:5&#8211;11 uses the father-son discipline model (from Prov&#160;3:11&#8211;12) to interpret Christian suffering as divine paternal love. The interpretive key in both OT and NT is love as the motive — the parent who disciplines is the parent who cares enough to endure the child&#8217;s displeasure.</p>",
        "25": "<p>&#8220;The righteous eat until they are satisfied, but the stomach of the wicked goes hungry.&#8221; The closing verse of ch13 restates the chapter&#8217;s consistent theme through the lens of physical satisfaction and hunger. This is the Deuteronomic covenant blessing in its most basic form: those who align with YHWH&#8217;s order eat their fill (Deut&#160;28:1&#8211;14); those who defy it go hungry (Deut&#160;28:15&#8211;18). The bodily dimension of covenant blessing is not spiritualized away in the wisdom tradition — the moral order of the universe has consequences that are physically experienced.</p>"
    },
    "14": {
        "1": "<p>&#8220;A wise woman builds up her household (<i>bāntāh bêtāh</i>), but a foolish woman tears hers down with her own hands.&#8221; The wise/foolish woman contrast at the household level mirrors the extended personifications of ch9 (Wisdom&#8217;s feast vs. Folly&#8217;s invitation) and anticipates the portrait of the capable wife in 31:10&#8211;31. The verb <i>bānāh</i> (to build) is used of building cities, temples, and dynasties; the household (<i>bayit</i>) can be both the physical structure and the extended family unit. The foolish woman&#8217;s self-destruction &#8220;with her own hands&#8221; emphasizes that folly is not passive failure but active self-demolition.</p>",
        "2": "<p>&#8220;Whoever walks in uprightness fears the LORD, but whoever is crooked in his ways despises him.&#8221; This verse encodes the book&#8217;s fundamental equation: the moral quality of one&#8217;s life (upright vs. crooked) is a direct index of one&#8217;s relationship to YHWH (fear vs. despise). The two-ways moral geography of Proverbs (straight vs. crooked paths) is here made explicitly theological: the direction one walks discloses one&#8217;s fundamental orientation toward YHWH. This is the practical expression of the thesis in 1:7: the fear of the LORD produces the upright walk; contempt for YHWH produces the crooked path.</p>",
        "3": "<p>&#8220;A fool&#8217;s talk brings punishment upon himself, but the lips of the wise protect them.&#8221; The rod-of-pride image (<i>ḥōṭer gāʾᵃwāh</i> = branch/shoot of pride) suggests that the fool&#8217;s speech grows from the root of pride and becomes the instrument of their own punishment — they beat themselves with it. This is the auto-punitive pattern seen throughout the sentence-collection: the fool&#8217;s characteristic sin is the cause of their characteristic punishment. The wise person&#8217;s lips become a <i>miš&lsquo;meret</i> (guard) — protecting them from the consequences that would otherwise follow carelessly spoken words.</p>",
        "4": "<p>&#8220;Where there are no oxen, the stall is clean, but much increase comes through the strength of an ox.&#8221; One of Proverbs&#8217; most pragmatic verses — the mess created by productive animals is the price of agricultural abundance. The agricultural economy of ancient Palestine was entirely dependent on oxen for plowing; a clean stall was the stall of the person who had sold or lost their oxen and thus could no longer farm effectively. The verse commends accepting the costs and complications that come with productive capacity. Applied broadly: productive life is messy; a mess-free life is often a fruitless life.</p>",
        "5": "<p>&#8220;An honest witness does not lie, but a false witness breathes out lies.&#8221; The ninth commandment (Exod&#160;20:16; Deut&#160;5:20) against false witness is one of the most frequently reinforced instructions in Proverbs (6:19; 12:17; 14:5, 25; 19:5, 9; 21:28; 25:18). The legal system of ancient Israel depended entirely on oral testimony; a false witness could destroy an innocent person and acquit the guilty. Proverbs&#8217; repeated return to this theme reflects the gravity of the threat: unchecked false witness is socially catastrophic because it corrupts justice at its root.</p>",
        "6": "<p>&#8220;A mocker looks for wisdom but does not find it, but knowledge comes easily to a person of understanding.&#8221; The mocker&#8217;s failure to find wisdom despite apparently seeking it reveals the paradox of wisdom-acquisition: the prerequisite for receiving wisdom is the teachable posture (the fear of the LORD, receptivity to correction) that the mocker&#8217;s essential character refuses to adopt. You cannot receive wisdom while maintaining contempt for its source and its teachers. The person of understanding (<i>nābôn</i>) encounters no such barrier — wisdom finds the person already oriented toward receiving it.</p>",
        "7": "<p>&#8220;Stay away from a foolish person — there is no knowledge on his lips.&#8221; The social-separation advice here is not social elitism but a recognition of wisdom&#8217;s positive content: time spent with the foolish yields nothing because there is nothing to receive. The advice echoes Ps&#160;1:1 (&#8220;blessed is the man who walks not in the counsel of the wicked&#8221;) and the principle of 13:20 (social environment shapes character). In a world without books, the primary medium of wisdom-transmission was oral — the company one kept was the curriculum one received.</p>",
        "8": "<p>&#8220;The wisdom of the prudent is to understand his way, but the folly of fools is self-deception (<i>mirmāh</i>).&#8221; Wisdom&#8217;s practical function is self-knowledge: the prudent person understands <i>darkô</i> (his own way, path, situation) — they read themselves and their circumstances accurately. Folly&#8217;s signature is self-deception: the fool does not know themselves because their inner assessment faculty is corrupted. This corresponds to the prophetic diagnosis: Israel&#8217;s sin began with self-deception about their own condition (Jer&#160;17:9: &#8220;the heart is deceitful above all things&#8221;; Ezek&#160;33:10&#8211;11).</p>",
        "9": "<p>&#8220;Fools scoff at making amends for sin (<i>ʾāšām</i>), but among the upright there is goodwill.&#8221; The <i>ʾāšām</i> (guilt offering, reparation offering — the technical term for the sacrifice that makes amends for specific sins, Lev&#160;5&#8211;6) is here in a wisdom context: fools mock the whole category of moral repair and reparation. The upright, by contrast, create an atmosphere of mutual goodwill (<i>rāṣôn</i>) because they take moral accountability seriously. The verse provides a wisdom-theology perspective on the sacrificial system: the offering exists because the moral community requires repair mechanisms.</p>",
        "10": "<p>&#8220;Each heart knows its own sorrow, and no outsider can fully share its joy.&#8221; One of the most psychologically acute observations in Proverbs — the irreducible privacy of the inner life. The intimacy of <i>lēb</i> (heart, the center of thought and will) means that even the best human understanding of another&#8217;s suffering is partial. This verse stands against all theological systems that claim to fully account for another&#8217;s pain. It anticipates Job&#8217;s frustration with friends who think they understand his suffering from the outside (Job&#160;16:2&#8211;4) and the prophetic tradition&#8217;s acknowledgment of the mystery of individual suffering.</p>",
        "11": "<p>&#8220;The household of the wicked will be ruined, but the tent of the upright will flourish (<i>yipraḥ</i>).&#8221; The contrast between &#8220;household (<i>bayit</i>)&#8221; (a permanent structure) and &#8220;tent (<i>ʾōhel</i>)&#8221; (a temporary structure) is deliberately inverted in the outcome: the permanent house of the wicked is ruined; the seemingly-temporary tent of the upright blooms and flourishes. The inversion challenges appearances: institutional solidity is no guarantee of divine favor, and apparent fragility is no barrier to blessing. The tent imagery carries resonance from the patriarchal narratives where the righteous lived in tents.</p>",
        "12": "<p>&#8220;There is a path that seems right to a person, but it leads to death in the end.&#8221; One of the most diagnostically important proverbs in the entire book (repeated in 16:25). The verse targets the universal human tendency to trust subjective moral self-assessment — the path that &#8220;seems right&#8221; is not right. The Jeremiah tradition states the same insight: &#8220;the heart is deceitful above all things and desperately sick — who can understand it?&#8221; (Jer&#160;17:9). The verse is a perpetual warning against moral self-sufficiency and the wisdom tradition&#8217;s case for external correction, community counsel, and the fear of the LORD as correctives to subjective self-assessment.</p>",
        "13": "<p>&#8220;Even in laughter the heart may ache, and the end of joy can be sorrow.&#8221; The wisdom tradition&#8217;s recognition of the co-presence of grief and gladness. The heart&#8217;s experience is not monochrome — laughter and aching can occupy the same moment. This verse participates in the realism about suffering that runs from the lament Psalms through Job and Ecclesiastes: joy and pain are not as separable as the sentimental tradition imagines. Ecclesiastes develops this theme extensively (Eccl&#160;2:2&#8211;3; 7:3&#8211;4), and the NT teaching on joy-in-suffering (Jas&#160;1:2&#8211;4; Rom&#160;5:3&#8211;5) presupposes exactly this complex interior reality.</p>",
        "14": "<p>&#8220;One who turns away from faithfulness is filled with the results of his own choices, but a good man finds satisfaction within himself.&#8221; The retributive organic logic: the backslider (<i>sûg lēb</i> = the one whose heart turns away) is filled with (<i>yiśbāʿ</i>) his own ways. The same verb <i>śābaʿ</i> (to be satisfied, filled) used of blessing in positive contexts (13:4, 25) here describes the backslider gorging on the bitter fruit of his own choices. The &#8220;good man&#8221; finds satisfaction from within himself — not from external circumstances but from the integrity of his own character.</p>",
        "15": "<p>&#8220;The naive person believes everything he hears, but the prudent person gives careful thought to his steps.&#8221; Critical discernment — the ability to evaluate what one hears before acting on it — is a crucial wisdom skill. In a world of oral culture where information was transmitted through social networks, the ability to evaluate the reliability of reports was a survival skill. The naive person&#8217;s indiscriminate credulity makes them vulnerable to manipulation; the prudent person&#8217;s careful evaluation of information before taking action protects them. The contrast is not between trust and suspicion but between naive credulity and wise discernment.</p>",
        "16": "<p>&#8220;A wise man fears and turns from evil, but a fool is reckless and overconfident.&#8221; The fear that produces turning from evil is the fear of the LORD (1:7) applied to specific ethical choices. The wise person&#8217;s wariness (<i>yārēʾ</i>) is not timidity but the appropriate recognition of moral danger — the ability to see where a path leads before committing to it. The fool&#8217;s recklessness (<i>ʿōbēr</i> = passes beyond, transgresses) combined with overconfidence is the moral equivalent of crossing a bridge without checking whether it will hold.</p>",
        "17": "<p>&#8220;A quick-tempered person acts foolishly, and a person who schemes wickedly is despised.&#8221; Two contrasting failure modes: the impulsive fool who acts first and thinks later, and the calculated schemer who thinks too much toward wrong ends. The quick-tempered person&#8217;s actions proceed from passion without wisdom; the wickedly scheming person applies deliberation to evil purposes. Both end in ruin — the first through foolish action, the second through deserved social contempt. The wisdom ideal is deliberation in service of righteous ends.</p>",
        "18": "<p>&#8220;The naive end up with folly as their inheritance (<i>naḥᵃlû</i>), but the prudent are crowned with knowledge.&#8221; The inheritance-language is covenant language: <i>nāḥal</i> (to inherit as a lasting possession) is the word for the tribal land-inheritance of Israel (Num&#160;26:52&#8211;56; Josh&#160;13&#8211;21). The naive inherit folly as their permanent possession — not a punishment visited from outside but the consequence of what they have consistently chosen. The prudent receive a crown (<i>yaktîrû</i>) of knowledge — public honor marking them as those who have achieved the highest form of social recognition.</p>",
        "19": "<p>&#8220;Evil people will bow before those who are good, and the wicked at the gates of the righteous.&#8221; A future-oriented statement of moral reversal that anticipates the eschatological themes of the prophets (Isa&#160;60:14; Rev&#160;3:9). In the short term, the wicked often appear to prosper and the righteous to suffer (Ps&#160;73:3&#8211;12); Proverbs insists that the moral order will eventually produce the right alignment. The city gate as the place where the wicked bow is significant — the gate is the place of public honor and judgment, the location where status is publicly recognized.</p>",
        "20": "<p>&#8220;Even his neighbor dislikes a poor person, but a rich person has many friends.&#8221; A social observation about the reality of social relationships under economic pressure — not an endorsement but a description. The verse participates in Proverbs&#8217; consistent realism about how wealth shapes social relationships (13:7&#8211;8; 19:4, 6&#8211;7). The following verse (v21) provides the moral corrective: despising the poor is sin, regardless of the social reality that poverty creates distance. Proverbs names the social reality and then refuses to accept it as the moral norm.</p>",
        "21": "<p>&#8220;Whoever despises his neighbor is sinning, but blessed is whoever shows kindness to the poor.&#8221; The moral corrective to v20&#8217;s observation. The <i>ḥōnnēn ʿᵃnāwîm</i> (one who shows grace/kindness to the poor) is given the <i>ʾašrê</i> (blessed) designation — the beatitude that marks the person in right relationship with the divine order. This verse stands in the prophetic tradition of concern for the poor as a test of covenant faithfulness (Isa&#160;58:6&#8211;7; Amos&#160;5:11&#8211;12; Mic&#160;6:8) and anticipates Matt&#160;5:7 (&#8220;blessed are the merciful&#8221;) and 25:31&#8211;46.</p>",
        "22": "<p>&#8220;Do not those who plot evil go astray? But those who plan good find loyal love and faithfulness (<i>ḥesed wĕʾĕmet</i>).&#8221; The paired covenant-character terms <i>ḥesed wĕʾĕmet</i> (steadfast love and faithfulness — the Sinai attributes of YHWH from Exod&#160;34:6&#8211;7; cf. Prov&#160;3:3; 20:28) appear here as the reward of those who plan good. Covenant faithfulness toward others generates the same covenant faithfulness returned — the moral economy of the community reflects the character of YHWH himself. Planning evil generates wandering; planning good generates the relational fabric of covenant community.</p>",
        "23": "<p>&#8220;There is profit in all hard work, but mere talk leads only to poverty.&#8221; The work-vs.-words contrast is consistent across the wisdom tradition: <i>ʿeṣeb</i> (labor, toil — the word used in Gen&#160;3:16&#8211;19 for the painful labor that is part of the post-fall condition) produces profit (<i>môtār</i>, surplus); mere verbal activity (<i>dᵉbar śᵉpātayim</i> = words of lips) produces only lack. The verse does not valorize painful toil in itself but recognizes that genuine production requires genuine effort. &#8220;Mere talk&#8221; includes the verbosity that substitutes discussion of plans for the execution of them.</p>",
        "24": "<p>&#8220;The wealth of the wise is their crown (<i>ʿaṭeret ḥᵃkāmîm</i>), but fools&#8217; folly is folly to the end.&#8221; The crown of wisdom&#8217;s wealth is the public honor-marker of successful wisdom — material and social success as the visible expression of an interior orientation. The tautological closing &#8220;fools&#8217; folly is folly&#8221; has the quality of a verdict rather than an observation: foolishness is self-sealing, self-referential, unable to transcend itself. The wise grow wiser; the foolish become more thoroughly foolish. Wisdom and folly are not static states but dynamic trajectories.</p>",
        "25": "<p>&#8220;A truthful witness saves lives, but a false witness deals in lies.&#8221; The stakes of honest witness are life-or-death — literally so in a legal system where capital cases depended entirely on oral testimony. The Mosaic law required two or three witnesses for a capital conviction (Num&#160;35:30; Deut&#160;17:6; 19:15) and prescribed death for the false witness who sought to bring a capital charge (Deut&#160;19:16&#8211;21: the principle of <i>lex talionis</i> applied to false witness). Proverbs places the truthful witness in the category of life-saver — both literally in the courts and metaphorically in all speech contexts where accuracy preserves the innocent.</p>",
        "26": "<p>&#8220;The fear of the LORD is a source of strong confidence (<i>mibtaḥ ʿōz</i>), and his children will find refuge in him.&#8221; The fear of the LORD as the foundation of security is the practical application of the book&#8217;s thesis (1:7) to personal circumstances. <i>Mibtāḥ</i> (confidence, trust — the noun of <i>bāṭaḥ</i>, the trust-word of 3:5) combined with <i>ʿōz</i> (strength, a stronghold) gives the verse a military flavor: the fear-of-the-LORD is a fortified position. &#8220;His children&#8221; — both the literal children of the fear-of-YHWH practitioner and figuratively all who shelter in that relationship — find refuge (<i>maḥseh</i>, the standard word for divine protection in the Psalms, Ps&#160;46:1; 91:2).</p>",
        "27": "<p>&#8220;The fear of the LORD is a fountain of life (<i>mᵉqôr ḥayyîm</i>), turning one away from the traps of death.&#8221; Nearly identical to 13:14 (where the teaching of the wise is the fountain-of-life), making the equation explicit: wisdom&#8217;s teaching and the fear of the LORD are effectively the same thing. The fountain-of-life image applied to the fear of the LORD grounds wisdom-seeking in covenantal relationship: the source of life is YHWH himself, and the fear that keeps one in right relation to him is the source of the life that flows from him. The traps-of-death metaphor (snares laid by death for the unwary) appears also in Ps&#160;116:3 and 18:5.</p>",
        "28": "<p>&#8220;A large population is a king&#8217;s glory, but a prince is ruined by a lack of people.&#8221; A political-wisdom observation: in the ancient world, population size was directly correlated with economic and military power. The king&#8217;s glory (<i>hadar</i> = dignity, splendor) rested on a flourishing, numerous people; depopulation meant ruined tax base, empty armies, and declining agricultural production. This verse belongs to the royal-wisdom tradition that Proverbs contains alongside its domestic and personal wisdom — observations about governance and political order that were directly relevant in the court context where wisdom instruction was also practiced.</p>",
        "29": "<p>&#8220;Whoever is slow to anger shows great understanding, but a quick temper elevates foolishness.&#8221; The contrast between slow and quick anger appears in Jas&#160;1:19&#8211;20 (&#8220;be quick to hear, slow to speak, slow to anger, for the anger of man does not produce the righteousness of God&#8221;) and Prov&#160;15:18 and 16:32. The wisdom tradition consistently commends measured emotional response as the fruit of genuine understanding: the person who understands the situation fully is not provoked to premature anger. Impulsive anger is both a symptom and a cause of folly — it produces more foolish actions and reveals the underlying absence of self-mastery.</p>",
        "30": "<p>&#8220;A calm and contented heart brings health to the body, but envy eats away at the bones.&#8221; The physiological insight that emotional states have bodily effects is consistent with the Hebrew holistic anthropology in which the body and the inner life are not separated. <i>Qinʾāh</i> (envy, jealousy — also used of divine jealousy for exclusive loyalty) is here the most destructive interior state: it physically consumes the bones (the body&#8217;s structural support). Modern medicine confirms the correlation between chronic negative emotional states and physical disease. The calm heart (<i>lēb marpēʾ</i> = heart of healing/calm) produces the physical health that is wisdom&#8217;s gift (3:7&#8211;8).</p>",
        "31": "<p>&#8220;Whoever oppresses the poor insults their Maker, but whoever shows kindness to the needy honors him.&#8221; One of Proverbs&#8217; most theologically dense verses. The equation: treatment of the poor = treatment of the Creator. The &#8220;Maker (<i>ʿōśēhû</i>)&#8221; of the poor is YHWH — the poor person carries the image of their Maker, and how one treats the image-bearer is how one treats the image-original. This creation-theology of the poor runs through Prov&#160;17:5 (same verse) and Job&#160;31:13&#8211;15 (Job&#8217;s defense of his treatment of servants: &#8220;did not he who made me in the womb make him?&#8221;). Jesus inherits this tradition in Matt&#160;25:40 (&#8220;as you did it to one of the least of these... you did it to me&#8221;).</p>",
        "32": "<p>&#8220;The wicked are brought down by their own evil, but the righteous have hope even in death (<i>bᵉmôtô</i>).&#8221; The remarkable final clause — hope in death — reaches beyond the typical wisdom horizon. While most of Proverbs operates within the framework of this-worldly retribution, this verse hints at something that transcends death. The <i>māḥseh</i> (refuge) the righteous find &#8220;in his death&#8221; points toward the resurrection hope that would be explicitly articulated in later Second Temple Judaism and by Jesus (John&#160;11:25&#8211;26). It is one of the clearest hints in Proverbs that wisdom&#8217;s hope is not bounded by this life.</p>",
        "33": "<p>&#8220;Wisdom quietly rests (<i>tānûaḥ</i>) in the heart of the discerning, but it makes itself known even among fools.&#8221; The discerning person&#8217;s wisdom is interior and restful — it does not have to broadcast itself. The enigmatic second clause suggests that even in the company of fools, wisdom somehow makes itself apparent — either wisdom&#8217;s presence is so distinctive it cannot be hidden, or (reading &#8220;even among fools&#8221; as &#8220;it is known that wisdom is not there&#8221;) that its absence is equally apparent. Either way, wisdom is a quality that cannot be feigned over time: it either rests quietly in the heart or it is not there at all.</p>",
        "34": "<p>&#8220;Righteousness lifts a nation up (<i>yᵉrômem-gôy ṣᵉdāqāh</i>), but sin is a disgrace (<i>ḥerpāh</i>) to any people.&#8221; One of Proverbs&#8217; few explicitly national-political statements — the wisdom that elsewhere applies to individuals and households is here applied to the entire nation. The prophets make the same application at length (Isa&#160;1:21&#8211;26; Jer&#160;18:7&#8211;10; Amos&#160;5:21&#8211;24). The wisdom tradition and the prophetic tradition converge at this point: the moral character of a nation&#8217;s life determines its trajectory. This verse is one of the most frequently cited OT texts in political theology across the centuries.</p>",
        "35": "<p>&#8220;A king&#8217;s favor rests on a servant who acts wisely, but his anger falls on one who acts shamefully.&#8221; The royal-wisdom dimension of Proverbs (appropriate to its Solomonic origin and courtly context) surfaces: wisdom in the servant gains royal favor; shame brings royal anger. Joseph&#8217;s advancement from prison to the right hand of Pharaoh (Gen&#160;41:39&#8211;41) is the paradigmatic narrative of this principle. Daniel&#8217;s favor with Nebuchadnezzar (Dan&#160;1:20; 2:48) is another. The wisdom tradition was always partly oriented toward formation for public service in the royal court, and these verses give that aspiration its moral grounding.</p>"
    },
    "15": {
        "1": "<p>&#8220;A gentle answer turns away anger, but a harsh word stirs up wrath.&#8221; One of the most widely cited proverbs, grounded in the observation that escalation and de-escalation in human conflict are largely controlled by the register and tone of speech. The wisdom tradition&#8217;s emphasis on speech management reflects the reality that in small-scale communities where all relationships are long-term and interconnected, the management of conflict through careful speech is a survival skill. James&#160;1:19 (&#8220;slow to speak, slow to anger&#8221;) and the NT teaching on speech in community (Eph&#160;4:29&#8211;32) develop this principle theologically.</p>",
        "2": "<p>&#8220;The tongue of the wise presents knowledge rightly (<i>têṭîb daʿat</i>), but the mouth of fools gushes (<i>yabbîaʿ</i>) foolishness.&#8221; The contrast between measured delivery of knowledge and uncontrolled verbal overflow. <i>Nābîaʿ</i> (to bubble up, gush — the same root as wisdom&#8217;s pouring out in 1:23) applied to the fool&#8217;s speech: where wisdom pours out from a full and ordered source, the fool&#8217;s speech gushes unfiltered from a disordered interior. The quality of speech is determined by the quality of the interior life that produces it.</p>",
        "3": "<p>&#8220;The LORD&#8217;s eyes are everywhere (<i>bᵉkol-māqôm</i>), watching both the evil and the good.&#8221; Divine omniscience as a foundational ethical premise. YHWH&#8217;s comprehensive surveillance of human moral life — not as a threatening surveillance state but as the premise of moral accountability — runs through the Psalms (Ps&#160;139:1&#8211;12; 11:4; 33:13&#8211;15) and the prophets (Jer&#160;23:24; Amos&#160;9:1&#8211;4). Proverbs&#8217; placement of this statement among practical ethical instructions gives it a practical application: no behavior is unobserved, and the observer is the one to whom all give account. The verse grounds wisdom&#8217;s ethical instruction in the reality of divine moral governance.</p>",
        "4": "<p>&#8220;A wholesome tongue (<i>marpēʾ lāšôn</i>) is a tree of life (<i>ʿēṣ ḥayyîm</i>), but a twisted tongue crushes the spirit.&#8221; The fourth tree-of-life occurrence in Proverbs (3:18; 11:30; 13:12; 15:4), applied to healing speech. The tongue that heals is a life-giving source like the Eden tree; the tongue that is &#8220;twisted (<i>sᵉlep</i> = perversion)&#8221; crushes the spirit. Speech that carries the power of life-giving truth and comfort participates in the life-giving order of creation; speech that distorts reality is anti-creational, reducing the spirit of the hearer. The tree-of-life as the positive goal of all formative Proverbs instruction is here made available through the medium of wholesome speech.</p>",
        "5": "<p>&#8220;A fool rejects his father&#8217;s discipline, but whoever accepts correction shows good sense.&#8221; The father-son discipline frame (3:11&#8211;12; 13:1; 15:5) is the book&#8217;s most consistent pedagogical context. The fool&#8217;s rejection of discipline is not ignorance but active refusal; the person who accepts correction demonstrates <i>ʿārum</i> (prudence, the strategic intelligence of the capable person). The acceptance of correction requires a kind of ego-courage: it takes strength to acknowledge that you are wrong and adjust accordingly. The fool&#8217;s brittleness under correction is a form of weakness disguised as self-assertion.</p>",
        "6": "<p>&#8220;The household of the righteous holds great treasure (<i>ḥōsen rāb</i>), but the income of the wicked brings trouble (<i>nebekāh</i>).&#8221; The household as the economic unit where righteousness and wickedness respectively accumulate their outcomes. The righteous household&#8217;s great treasure is the covenant blessing made concrete; the wicked&#8217;s income brings <i>nebekāh</i> (trouble, disturbance — a word suggesting disruption and confusion). The income that flows from righteousness consolidates; the income that flows from wickedness is unstable and ultimately destructive even to its owner.</p>",
        "7": "<p>&#8220;The lips of the wise spread (<i>yᵉzārû</i>) knowledge, but the minds of fools do not.&#8221; The winnowing image (<i>zārāh</i>) for speech: wise lips scatter knowledge like winnowing grain into the air — distributing it broadly, separating the valuable from the worthless. The fool&#8217;s mind (<i>lēb</i>) has nothing to scatter because there is nothing within to spread. Wisdom&#8217;s generative quality — that it multiplies and extends itself through sharing — contrasts with folly&#8217;s sterility. The wise person who shares knowledge enriches the community; the fool can offer nothing.</p>",
        "8": "<p>&#8220;The LORD detests the sacrifice of the wicked, but the prayer of the upright is his delight.&#8221; The prophetic critique of empty ritual (1&#160;Sam&#160;15:22; Isa&#160;1:11&#8211;13; Hos&#160;6:6; Amos&#160;5:21&#8211;24; Mic&#160;6:6&#8211;8; Jer&#160;7:21&#8211;23) here appears in Proverbs&#8217; sentence-collection, confirming that the insight is a broad wisdom consensus, not merely prophetic polemic. The <i>tôʿᵃbāh</i> (abomination) vocabulary is the strongest possible negative assessment; the sacrifice of the wicked person is not merely ineffective but actively offensive to YHWH. The pairing with upright prayer confirms that the issue is not the ritual form but the interior character of the worshipper.</p>",
        "9": "<p>&#8220;The LORD detests the way of the wicked, but he loves whoever earnestly pursues righteousness.&#8221; The divine love-hate of v9 is the personal application of v8&#8217;s ritual-ethical principle: YHWH&#8217;s response to persons corresponds to his response to their actions. The word <i>rōdēp</i> (pursuing, chasing — the same word used of calamity pursuing sinners in 13:21) applied to righteousness: the person who hunts down righteousness with the same energy that calamity hunts sinners is the one God loves. The pursuit is active and effortful — not passive moral decency but the active chase after the right.</p>",
        "10": "<p>&#8220;There is harsh discipline for the one who leaves the right path, and whoever hates correction will die.&#8221; The moral stakes of leaving the path are presented with unusual sharpness: death for the correction-hater. The word <i>mûsār</i> (discipline) is the same as the father&#8217;s formative instruction throughout Proverbs (1:2&#8211;3, 8; 3:11); when refused, it becomes harsh punishment rather than gentle correction. The wisdom tradition presents discipline as the alternative to death: accept the lesser pain of formative correction now, or face the ultimate consequence of unformed character. The fork in the road is always available, but it closes as one goes further down the wrong path.</p>",
        "11": "<p>&#8220;Death (<i>šᵉʾôl</i>) and Destruction (<i>ʾᵃbaddôn</i>) lie open (<i>negdô</i>) before the LORD — how much more the hearts of people!&#8221; The <i>qal wāḥōmer</i> (light-to-heavy) argument: if even the most hidden realm — the underworld itself — is transparent to YHWH, the human heart has no hiding place. <i>ʾAbaddôn</i> (Destruction/Perdition) is the Sheol-synonym appearing also in Job&#160;26:6; 28:22; Ps&#160;88:11 and Rev&#160;9:11. The divine penetration of the underworld is a uniquely biblical claim against ancient Near Eastern cosmologies in which the underworld was a realm beyond the reach of the upper-world gods. YHWH&#8217;s jurisdiction extends everywhere: Ps&#160;139:8 (&#8220;if I make my bed in Sheol, you are there&#8221;).</p>",
        "12": "<p>&#8220;A mocker does not like being corrected and will not seek the company of the wise.&#8221; The mocker&#8217;s defining behavior pattern: the person who refuses correction will also avoid those who might correct them. This is the self-sealing character of folly described in 1:22 and 9:7&#8211;8: the mocker who rejects instruction also rejects its source. Wisdom&#8217;s community-formation (seek the company of the wise, 13:20) is actively resisted by the mocker&#8217;s social choices. The choice of social context and the choice of moral formation are not separate: who you choose to spend time with is who you choose to become.</p>",
        "13": "<p>&#8220;A joyful heart makes a bright face, but a crushed spirit shows in the countenance.&#8221; The face as the legible surface of the inner life — the Hebrew wisdom tradition consistently connects the exterior expression to the interior state. Nehemiah&#8217;s countenance revealed his grief before he spoke a word (Neh&#160;2:2); the faces of Daniel&#8217;s three friends were &#8220;not different from those of the other young men&#8221; after their vegetarian diet (Dan&#160;1:15) — physical wellness was externally visible. The verse is both an observation and an implicit instruction: cultivate the inner joy that produces the bright face, and address the broken spirit that produces the downcast countenance.</p>",
        "14": "<p>&#8220;A discerning heart is always seeking knowledge (<i>dōrēš daʿat</i>), but the mouth of a fool feeds on folly.&#8221; The discerning heart&#8217;s perpetual intellectual hunger for knowledge contrasts with the fool&#8217;s oral fixation on folly. <i>Dārash</i> (to seek, inquire, search — the same word used for seeking God in 2&#160;Chr&#160;7:14; Isa&#160;55:6) gives wisdom-seeking a quasi-devotional quality: the discerning person pursues knowledge with the same intensity that the devout seek YHWH. The fool&#8217;s appetite is self-consuming — feeding on what will not nourish, growing more foolish through what nourishes foolishness.</p>",
        "15": "<p>&#8220;All the days of the afflicted are miserable, but a joyful heart provides a constant feast.&#8221; One of the most striking of the better-than proverbs (not stated as &#8220;better than&#8221; but functioning equivalently): external circumstances (affliction, poverty) do not determine the quality of inner life; and inner quality (joyful heart) transforms the experience of whatever circumstances one inhabits. This is the wisdom tradition&#8217;s most important contribution to the theology of suffering: the inner life is not simply at the mercy of external events. Paul develops this in Phil&#160;4:11&#8211;12 (&#8220;I have learned, in whatever state I am, to be content&#8221;).</p>",
        "16": "<p>&#8220;Better to have little with the fear of the LORD than great wealth with turmoil (<i>ûmᵉhûmāh</i>).&#8221; The first of the ch15 better-than proverbs challenges the conventional correlation between wealth and wellbeing. The fear of the LORD with little is worth more than great wealth with <i>mᵉhûmāh</i> (turmoil, confusion, uproar — the word used of the divine panic that routs armies in battle, Deut&#160;7:23; 1&#160;Sam&#160;5:9, 11). Wealth without covenant order creates its own internal chaos. The Instruction of Amenemope similarly commends the contentment of the poor person with YHWH over the acquisitive anxiety of the rich.</p>",
        "17": "<p>&#8220;Better a simple meal where love is present than a lavish feast accompanied by hatred.&#8221; The <i>ṭôb-min</i> (better-than) comparison of relational quality over material abundance continues the theme of v16. <i>ʾōraḥ yārāq</i> (a portion of herbs/vegetables — the simplest possible fare) with <i>ʾahᵃbāh</i> (love) versus <i>šôr ʾābûs</i> (fattened ox — the most lavish feast possible) with <i>śinʾāh</i> (hatred). The verse is the dietary inversion of the wisdom feast in ch9: wisdom&#8217;s genuine invitation is to the simple meal made rich by relationship; the lavish feast of folly or the wicked is poisoned by the hatred that pervades it.</p>",
        "18": "<p>&#8220;A hot-tempered man stirs up conflict (<i>yᵉgāreh-māḏôn</i>), but whoever is slow to anger quiets it.&#8221; The social-environment function of emotional temperament: the hot-tempered person is a social accelerant, raising the temperature of every situation they enter; the slow-to-anger person is a social thermostat that lowers temperatures. James&#160;4:1&#8211;2 traces conflict to the passionate desires of the hot-tempered, while Prov&#160;26:20&#8211;21 compares the quarrelsome person to fire-stoking wood. The wisdom tradition consistently presents emotional self-regulation as one of the most socially valuable capacities a person can develop.</p>",
        "19": "<p>&#8220;The path of the lazy is like a hedgerow of thorns (<i>kᵉmeśûkat qôṣ</i>), but the road of the upright is a level highway.&#8221; The path imagery is consistent throughout Proverbs (2:12&#8211;15; 4:18&#8211;19; 12:28). The sluggard&#8217;s path is hedged with thorns — not because the world has placed obstacles there but because the sluggard&#8217;s way of encountering the world turns everything into an obstacle. The upright person&#8217;s highway (<i>sᵉlulāh</i> = built up, paved road) is clear — not because the terrain is naturally easier but because uprightness of character creates the capacity to navigate what others find impassable.</p>",
        "20": "<p>&#8220;A wise son brings his father joy (<i>yᵉśammah ʾāb</i>), but a foolish man shows contempt for his mother.&#8221; The father-joy / mother-contempt pairing (cf. 10:1; 17:21, 25; 23:24&#8211;25) frames the domestic consequences of wisdom and folly in the most personal terms. The joy the wise son generates in the father is the Proverbs counterpart to the parable of the prodigal son (Luke&#160;15:20&#8211;24): &#8220;while he was yet a long way off, his father saw him and felt compassion.&#8221; The father who runs to the returning son is experiencing the joy of the wise son&#8217;s return that every verse about the wise son is pointing toward.</p>",
        "21": "<p>&#8220;Folly is entertaining to a person who lacks judgment (<i>ḥᵃsar-lēb</i>), but a person of understanding walks straight.&#8221; <i>Ḥᵃsar-lēb</i> (lacking heart/mind — the same term used of the naive young man seduced by the adulteress in 7:7) finds folly entertaining because there is no interior capacity to recognize its danger. The Hebrew tradition&#8217;s concept of the &#8220;heart&#8221; (<i>lēb</i>) as the center of moral judgment means that lacking it is lacking the basic equipment for moral navigation. The person of understanding walks a straight path not because the terrain is simple but because they can see it clearly.</p>",
        "22": "<p>&#8220;Plans fail where there is no guidance (<i>ʾên sôd</i>), but with many counselors they succeed.&#8221; The corporate wisdom principle of 11:14; 20:18; 24:6 — individual wisdom is inadequate for major decisions; the community of counselors provides the checks and perspectives that individual blindspots require. <i>Sôd</i> (intimate counsel, the inner circle — cf. 3:32 where the upright are in YHWH&#8217;s <i>sôd</i>; and Jer&#160;23:18 for the divine council) — the inner circle of trusted wise counselors is the human analog of the divine council, a structure of accountability and wisdom that no individual can adequately replicate alone.</p>",
        "23": "<p>&#8220;A person finds joy in giving the right answer (<i>maʿᵃneh-pîhû</i>), and how good is a timely word (<i>dābār bᵉʿittô</i>)!&#8221; The joy of the apt word at the right moment — the convergence of truth, timing, and person that makes speech genuinely helpful. The wisdom tradition commends not only speaking the truth but speaking it at the right time and in the right way. Ecclesiastes elaborates this: &#8220;there is a time to speak and a time to keep silence&#8221; (Eccl&#160;3:7). The <i>dābār bᵉʿittô</i> (word in its time) is the ideal of wise speech — like apples of gold in settings of silver (25:11).</p>",
        "24": "<p>&#8220;The way of life leads upward (<i>lᵉmaʿlāh</i>) for the wise, so that they may avoid Sheol below (<i>lᵉmattāh</i>).&#8221; The vertical cosmology — upward toward life, downward toward Sheol — gives wisdom&#8217;s two-ways geography a vertical dimension. The normal path imagery of the horizontal journey is here supplemented by the ascent/descent axis. This vertical imagery aligns with the later apocalyptic tradition (Dan&#160;12:2: &#8220;those who sleep in the dust of the earth shall awake, some to everlasting life&#8221;) and ultimately with the NT&#8217;s language of resurrection as ascent. The wise person&#8217;s upward path is not merely moral progress but a directional movement away from death.</p>",
        "25": "<p>&#8220;The LORD will pull down the house of the proud, but he maintains (<i>yaṣṣîb</i>) the widow&#8217;s property lines (<i>gᵉbûl ʾalmānāh</i>).&#8221; The widow&#8217;s property as a specific object of divine protection is grounded in the Mosaic social legislation: YHWH is explicitly the defender of widows and orphans (Exod&#160;22:22&#8211;24; Deut&#160;10:18; 27:19; Isa&#160;1:17). Proverbs applies this divine advocacy to the practical matter of land boundaries (cf. 22:28; 23:10&#8211;11) — the widow&#8217;s neighbor who moves the boundary stone defrauds her of her only economic resource. YHWH himself acts as the boundary-setter who protects the most economically vulnerable from those who would take advantage of them.</p>",
        "26": "<p>&#8220;The LORD detests the plans (<i>maḥšᵉbôt</i>) of the wicked, but pure words are pleasing to him.&#8221; The contrast between wicked plans and pure words places both speech and deliberation under divine moral evaluation. <i>Tāhôr</i> (pure, ritually clean — the purity vocabulary of Leviticus applied here to speech) — pure speech is categorically acceptable to YHWH just as a pure offering is. The integration of ritual purity language with ethical speech standards reflects the wisdom tradition&#8217;s consistent tendency to treat the whole of life — ritual and ethical, speech and action — as a unified moral sphere under divine evaluation.</p>",
        "27": "<p>&#8220;Whoever is greedy for gain (<i>bōṣēaʿ bāṣaʿ</i>) brings trouble to his own household, but whoever refuses bribes will live.&#8221; The anti-bribery instruction is consistent throughout the wisdom tradition (17:8, 23; Exod&#160;23:8; Deut&#160;16:19; Isa&#160;1:23) and has particular application in the context of court officials and judges. The Mosaic prohibition against bribery (Exod&#160;23:8: &#8220;a bribe blinds the officials and subverts the cause of those who are in the right&#8221;) is grounded in the character of YHWH himself as the one who &#8220;takes no bribe&#8221; (Deut&#160;10:17). The bribe-refuser who &#8220;will live&#8221; echoes the covenant promise: right living produces life.</p>",
        "28": "<p>&#8220;The heart of the righteous weighs its answer carefully (<i>yehgeh laʿᵃnôt</i>), but the mouth of the wicked blurts out evil.&#8221; The deliberative process of the righteous — the heart weighs, considers, meditates before the mouth speaks — contrasts with the wicked&#8217;s unfiltered verbal expression of inner evil. <i>Hāgāh</i> (to meditate, mutter, muse — the same word as Ps&#160;1:2, &#8220;meditating on the law day and night&#8221;) applied to careful speech: the wise person is someone whose interior deliberative process is as attentive as the Psalmist&#8217;s meditation on Torah. The words that emerge from such a process are weighted and trustworthy.</p>",
        "29": "<p>&#8220;The LORD is distant (<i>rāḥôq</i>) from the wicked, but he hears the prayer of the righteous.&#8221; Divine responsiveness calibrated to moral character — not as an arbitrary rule but as the natural consequence of covenant relationship. The wicked, by their persistent rejection of YHWH&#8217;s order, create the distance they experience. The righteous, by covenant faithfulness, maintain the relationship in which their prayers are heard. Ps&#160;34:15&#8211;16 makes the same point: &#8220;the eyes of the LORD are on the righteous and his ears open to their cry... the face of the LORD is against those who do evil.&#8221; This is not favoritism but the relational consequence of covenant relationship or its rejection.</p>",
        "30": "<p>&#8220;Bright eyes (<i>mᵉʾôr ʿênayim</i>) make the heart glad, and good news (<i>šᵉmûʿāh ṭôbāh</i>) refreshes (<i>tᵉdaššen</i>) the whole body.&#8221; The physiological effect of positive sensory experience — bright eyes (someone else&#8217;s, or one&#8217;s own joyful seeing?) and good news — on the whole body. <i>Dāšēn</i> (to be fat, well-nourished — the same word as 13:4 for the diligent soul&#8217;s rich satisfaction) applied to the body&#8217;s response to good news: it is experienced as rich nourishment. The verse reflects the Hebrew holistic anthropology in which emotional and informational inputs have immediate physiological effects. Good news as body-medicine anticipates modern mind-body medicine.</p>",
        "31": "<p>&#8220;The ear that heeds life-giving correction will find its home (<i>tālin</i>) among the wise.&#8221; The receptive ear as the organ of social placement: the person who listens to correction will find their permanent dwelling (<i>lîn</i> = to lodge, to spend the night, to take up residence) among the wise. Wisdom is a community, not merely a set of qualities — to become wise is to join the community of those who are wise. The ear-that-heeds is the point of entry into that community. This communal dimension of wisdom is consistent throughout Proverbs: the wise are a society that the teachable can enter through the posture of receptivity.</p>",
        "32": "<p>&#8220;Whoever refuses correction despises himself (<i>mōʾēs napšô</i>), but whoever accepts reproof gains insight.&#8221; The self-destructive logic of refusing correction: to refuse the wisdom that could form you is to hold your own soul in contempt. The strongest statement of wisdom&#8217;s consistent argument that correction-refusal is fundamentally self-interested in the wrong direction — the fool who refuses instruction &#8220;chooses death&#8221; in the most self-interested way imaginable while believing he is protecting his dignity. Accepting reproof (<i>qōneh lēb</i> = gains heart/mind) is the act of genuine self-love.</p>",
        "33": "<p>&#8220;The fear of the LORD is training in wisdom (<i>mûsar ḥokmāh</i>), and humility comes before honor.&#8221; The closing verse of ch15 makes the connection explicit: fear-of-the-LORD is not only the beginning of wisdom (1:7; 9:10) but its ongoing discipline and formation — the continuous tutorial that shapes character over a lifetime. &#8220;Humility comes before honor&#8221; is the Proverbs formulation of what Jesus states as a kingdom principle (Matt&#160;23:12: &#8220;whoever exalts himself will be humbled, and whoever humbles himself will be exalted&#8221;). The closing verse connects the book&#8217;s central theme (fear of the LORD) to the social outcome (honor through humility) that wisdom produces.</p>"
    }
}

existing = load_comm('mkt-context', 'proverbs')
merge_comm(existing, new_data)
save_comm('mkt-context', 'proverbs', existing)

for ch in sorted(new_data.keys(), key=int):
    vv = new_data[ch]
    have = sum(1 for v in vv if v in existing.get(ch, {}))
    print(f'  ch{ch}: {have}/{len(vv)} verses present')
